import { useEffect, useRef, useState } from "react";
import axios from "axios";
import ChatHeader from "./ChatHeader";
import ChatInput from "./ChatInput";
import Message from "./Message";
import ScratchButton from "./ScratchButton";
import TypingIndicator from "./TypingIndicator";

const API_URL = "http://localhost:5000/chat";

function toApiHistory(messages) {
  return messages.map((msg) => ({
    role: msg.sender === "ai" ? "assistant" : "user",
    content: msg.text,
  }));
}

export default function ChatBox({ emotion }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [chatStarted, setChatStarted] = useState(false);
  const [showGame, setShowGame] = useState(false);

  const chatRef = useRef();
  const greetingSentRef = useRef(false);

  useEffect(() => {
    chatRef.current?.scrollTo({
      top: chatRef.current.scrollHeight,
      behavior: "smooth",
    });
  }, [messages, loading, showGame]);

  useEffect(() => {
    if (!emotion || greetingSentRef.current) return;

    greetingSentRef.current = true;

    const fetchOpeningMessage = async () => {
      setLoading(true);

      try {
        const res = await axios.post(API_URL, {
          emotion,
          history: [],
        });

        setMessages([
          {
            sender: "ai",
            text: res.data.message,
          },
        ]);
        setChatStarted(true);
      } catch {
        setMessages([
          {
            sender: "ai",
            text: "Xin chào 👋 Mình là Larry!\nBạn có muốn kể cho Larry nghe hôm nay thế nào không?",
          },
        ]);
        setChatStarted(true);
      } finally {
        setLoading(false);
      }
    };

    fetchOpeningMessage();
  }, [emotion]);

  const sendMessage = async () => {
    if (!input.trim() || loading || !emotion) return;

    const text = input.trim();
    const updatedMessages = [
      ...messages,
      {
        sender: "user",
        text,
      },
    ];

    setMessages(updatedMessages);
    setInput("");
    setLoading(true);

    try {
      const res = await axios.post(API_URL, {
        emotion,
        history: toApiHistory(updatedMessages),
      });

      const aiText = res.data.message;

      setMessages((prev) => [
        ...prev,
        {
          sender: "ai",
          text: aiText,
        },
      ]);

      if (/scratch|trò chơi|chơi cùng larry|thư giãn/i.test(aiText)) {
        setShowGame(true);
      }
    } catch {
      setMessages((prev) => [
        ...prev,
        {
          sender: "ai",
          text: "Ôi không! Larry gặp chút trục trặc 😅\nBạn thử gửi lại nhé!",
        },
      ]);
    }

    setLoading(false);
  };

  return (
    <div className="chat-window">
      <ChatHeader />

      <div ref={chatRef} className="chat-messages">
        {!emotion && (
          <p className="waiting-hint">
            👀 Larry đang chờ nhìn thấy bạn qua camera...
          </p>
        )}

        {messages.map((msg, index) => (
          <Message key={index} sender={msg.sender} text={msg.text} index={index} />
        ))}

        {loading && <TypingIndicator />}
      </div>

      {chatStarted && (
        <ChatInput
          value={input}
          onChange={setInput}
          onSend={sendMessage}
          disabled={loading}
        />
      )}

      {showGame && <ScratchButton />}
    </div>
  );
}
